//create page load listener
window.onload = init;
// Job card 
// ======================================================================
var job_card = document.getElementById("jobs_wrapper")
// var companyList = document.getElementById("companyList")
// ======================================================================
// Job Object
var jobs = [];
// Locations
var locations = [];
var roles = [];
var companies = [];
// Init
function init() {
    const endpoint = './assets/json/data.json';
    var xhr = new XMLHttpRequest();
    xhr.open('GET', endpoint, true);
    xhr.responseType = 'json';
    xhr.onload = function () {
        if (xhr.status === 200) {
            const data = xhr.response;
            jobs = data.jobs;
            console.log(jobs)
            // Job card
            jobCard(jobs)
            // Jobs Filter
            // jobFilter(jobs, 'Toronto', 'Full Time');
            // Jobs Sort
            // jobSort(jobs)
            // Delete JOb
            jobDelete(jobs, 2);

            // Job list
            dropDownList(jobs);

        } else {
            // job_card.innerHTML += 
            job_card.innerHTML += `<p>Failed Loading</p>`;
        }
    };
    // console.log(jobs);
    xhr.send(null);
}
// Job Cards
function jobCard(jobs) {
    const total_jobs = document.getElementById('home_total_jobs')
    total_jobs.innerHTML = `<p> Total ${jobs.length} jobs posted: today`
    // content
    $html =
        jobs.forEach(jobs => {
            // Jobs cards
            job_card.innerHTML += `
<div class="job_card">
<i class="fa-regular fa-star icon"></i>
              <div class="logo">
                <img src="./assets/img/company/${jobs.logo}" alt="" />
              </div>
                <div class="job_details">
                <h3 class="title">${jobs.title}</h3>
                <h4 class="company">${jobs.company}</h4>
                <div class="location_type">
                  <span class="badge">${jobs.location}</span>
                  <span class="badge1">${jobs.type}</span>
                  <p class="description">${jobs.description}
                  </p>
                  <p class="ago">${jobs.posted}</p>
                </div>
              </div>
              </div>
            `;

        });
}
// Filters
function jobFilter(jobs, location, type) {
    const filtered = jobs
        .filter(job => job.type === type)
        .filter(job => job.location === location)
        .sort((a, b) => a.title.localeCompare(b.title));

    // console.log(filtered)
}

console.log(jobs)
// Sort

function jobSort(select) {
    console.log(select.value)
    const sortJobs = jobs
    .filter(job=>job.location === select.value)
    jobCard(sortJobs)
}
